{
  "summary": "This paper introduces Continual Knowledge Learning (CKL), a novel continual learning framework aimed at updating large language models' internal knowledge with new and updated information while preserving invariant facts. It proposes new benchmark datasets and a metric (FUAR) to evaluate forgetting and knowledge acquisition, and extensively compares continual learning methods, finding parameter-expansion approaches most effective despite memory inefficiency challenges.",
  "strengths": [
    {
      "point": "Novel formulation of continual knowledge learning problem",
      "evidence": "The paper clearly defines CKL as a new continual learning problem focused on updating LM knowledge through continual pretraining on new corpora."
    },
    {
      "point": "Comprehensive benchmark and metric design",
      "evidence": "Introduction of INVARIANT, UPDATED, and NEW LAMA datasets along with the FUAR metric enables systematic evaluation of forgetting, updating, and acquisition of knowledge."
    },
    {
      "point": "Extensive empirical evaluation of diverse continual learning methods",
      "evidence": "The paper adapts and compares regularization, rehearsal, and parameter-expansion methods across multiple LM architectures and settings."
    },
    {
      "point": "Insightful findings on effectiveness of parameter-expansion methods",
      "evidence": "Parameter-expansion approaches outperform others in balancing forgetting and learning new knowledge, highlighting unique CKL challenges."
    }
  ],
  "weaknesses": [
    {
      "point": "Lack of comparison with recent targeted knowledge editing methods",
      "evidence": "The paper does not discuss or empirically compare CKL with fine-grained knowledge patching or fact correction approaches."
    },
    {
      "point": "Insufficient justification and analysis of dataset choices",
      "evidence": "The rationale for selecting the CC-RECENT NEWS corpus (D1) and its domain impact on CKL performance is not thoroughly explored."
    },
    {
      "point": "Missing ablation and sensitivity analysis of FUAR metric",
      "evidence": "No experiments investigate how varying the weighting of forgetting versus acquisition components affects evaluation outcomes."
    },
    {
      "point": "Baselines do not include all relevant parameter-efficient tuning methods",
      "evidence": "Methods like prefix tuning or adapters beyond LoRA are omitted, limiting the strength of claims about parameter-expansion superiority."
    },
    {
      "point": "Limited exploration of rehearsal strategies",
      "evidence": "Rehearsal baselines only mix old data uniformly without testing different mixing ratios or curricula, possibly underestimating rehearsal potential."
    },
    {
      "point": "Multi-phase continual learning experiments lack mitigation analysis",
      "evidence": "No investigation into alternative parameter-expansion strategies (e.g., parameter sharing or pruning) to address memory inefficiency and forgetting."
    },
    {
      "point": "Reproducibility hindered by missing hyperparameter and dataset construction details",
      "evidence": "Key hyperparameters and dataset filtering/alignment procedures are not sufficiently described."
    },
    {
      "point": "Clarity issues in metric explanation and terminology",
      "evidence": "FUAR metric definition is terse and the distinction between invariant and updated knowledge is inconsistently explained."
    },
    {
      "point": "Limited analysis of catastrophic forgetting mechanisms",
      "evidence": "The paper quantifies forgetting but does not analyze underlying causes such as parameter drift or representation changes."
    },
    {
      "point": "Generalisability concerns due to limited languages and architectures",
      "evidence": "Experiments are restricted to English and two LM architectures without discussion of multilingual or encoder-only models."
    },
    {
      "point": "Domain shift effects between original and new corpora not explored",
      "evidence": "Differences between D0 (general) and D1 (news) corpora and their impact on forgetting and learning are not analyzed."
    },
    {
      "point": "Limited empirical evaluation on downstream task impact",
      "evidence": "Claims about CKL improving knowledge-intensive downstream tasks lack thorough empirical support."
    }
  ],
  "questions": [
    {
      "question": "How does CKL compare empirically and conceptually with targeted knowledge editing methods?",
      "motivation": "Understanding this would clarify CKL's novelty and practical advantages over fine-grained fact correction approaches."
    },
    {
      "question": "Can the memory inefficiency of parameter-expansion methods be mitigated through parameter sharing or pruning?",
      "motivation": "Addressing this is critical for scaling CKL to multiple continual learning phases in real-world applications."
    },
    {
      "question": "How sensitive are the evaluation results to the FUAR metric formulation and weighting?",
      "motivation": "This affects the robustness of conclusions drawn about method effectiveness."
    },
    {
      "question": "How does domain shift between original and continual pretraining corpora influence forgetting and knowledge acquisition?",
      "motivation": "Real-world continual learning often involves domain shifts; understanding this impact is essential for general applicability."
    }
  ],
  "scores": {
    "correctness": 3,
    "novelty": 3,
    "recommendation": "borderline",
    "confidence": 3
  }
}
